              ))}
            {renderSlots.map((i) =>
              reveal ? (
                <feImage
                  height="0.001"
                  key={`mask-${i}`}
                  preserveAspectRatio="none"
                  ref={(el) => {
                    slotsRef.current[i].feMask = el;
                  }}
                  result={`mask${i}`}
                  width="0.001"
                  x="0"
                  y="0"
                />
              ) : (
                <feFlood
                  floodColor="black"
                  floodOpacity="1"
                  height="0.001"
                  key={`mask-${i}`}
                  ref={(el) => {
                    slotsRef.current[i].feFlood = el;
                  }}
                  result={`mask${i}`}
                  width="0.001"
                  x="0"
                  y="0"
                />
              )
            )}
            <feMerge result="unionMask">
              {renderSlots.map((i) => (
                <feMergeNode in={`mask${i}`} key={`mn-${i}`} />
              ))}
            </feMerge>
            {reveal ? (
              <feComposite in="lensResult" in2="unionMask" operator="in" />
            ) : (
              <>
                <feComposite
                  in="lensResult"
                  in2="unionMask"
                  operator="in"
                  result="lensClipped"
                />
                <feComposite
                  in="SourceGraphic"
                  in2="unionMask"
                  operator="out"
                  result="holedSG"
                />
                <feComposite in="lensClipped" in2="holedSG" operator="over" />
              </>
            )}
          </filter>
        </defs>
        </svg>
      )}
    </div>
  );
}

export { Glass, generateLensMap, isSafariBrowser, useGlassDark, useHydrated };
export type { GlassDynamics, MapParams };

type Subscriber = (value: number) => void;

const VELOCITY_RESET_MS = 80;

class MotionValue {
  private current: number;
  private prevTime = 0;
  private velocityValue = 0;
  private subs = new Set<Subscriber>();
  private cancelFn: (() => void) | null = null;

  constructor(initial: number) {
    this.current = initial;
  }

  get(): number {
    return this.current;
  }

  getVelocity(): number {
    if (performance.now() - this.prevTime > VELOCITY_RESET_MS) {
      return 0;
    }
    return this.velocityValue;
  }

  set(next: number, timestamp = performance.now()) {
    const elapsed = timestamp - this.prevTime;
    if (elapsed > VELOCITY_RESET_MS) {
      this.velocityValue = 0;
    } else if (elapsed > 0) {
      const dt = Math.min(Math.max(elapsed, 8), 30);
      this.velocityValue = ((next - this.current) / dt) * 1000;
    }
    this.prevTime = timestamp;
    this.current = next;
    for (const fn of this.subs) {
      fn(next);
    }
  }

  jump(next: number) {
    this.stop();
    this.velocityValue = 0;
    this.prevTime = performance.now();
    this.current = next;
    for (const fn of this.subs) {
      fn(next);
    }
  }

  on(fn: Subscriber): () => void {
    this.subs.add(fn);
    return () => this.subs.delete(fn);
  }

  setCancel(fn: (() => void) | null) {
    this.cancelFn = fn;
  }

  stop() {
    this.cancelFn?.();
    this.cancelFn = null;
  }
}

function cubicBezier(x1: number, y1: number, x2: number, y2: number) {
  const cx = 3 * x1;
  const bx = 3 * (x2 - x1) - cx;
  const ax = 1 - cx - bx;
  const cy = 3 * y1;
  const by = 3 * (y2 - y1) - cy;
  const ay = 1 - cy - by;
  const sampleX = (t: number) => ((ax * t + bx) * t + cx) * t;
  const sampleY = (t: number) => ((ay * t + by) * t + cy) * t;
  const sampleDX = (t: number) => (3 * ax * t + 2 * bx) * t + cx;
  return (x: number) => {
    if (x <= 0) {
      return 0;
    }
    if (x >= 1) {
      return 1;
    }
    let t = x;
    for (let i = 0; i < 8; i++) {
      const err = sampleX(t) - x;
      if (Math.abs(err) < 1e-6) {
        return sampleY(t);
      }
      const d = sampleDX(t);
      if (Math.abs(d) < 1e-6) {
        break;
      }
      t -= err / d;
    }
    let lo = 0;
    let hi = 1;
    t = x;
    while (hi - lo > 1e-6) {
      if (sampleX(t) < x) {
        lo = t;
      } else {
        hi = t;
      }
      t = (lo + hi) / 2;
    }
    return sampleY(t);
  };
}

const glassEase = cubicBezier(0.22, 1.15, 0.36, 1.06);

const PRESS_DURATION = 0.32;
const RELEASE_DURATION = 0.52;
const TRAVEL_DURATION = 0.6;

function tween(
  value: MotionValue,
  to: number,
  duration: number,
  ease: (t: number) => number,
  onComplete?: () => void
): () => void {
  value.stop();
  if (duration <= 0) {
    value.jump(to);
    onComplete?.();
    return () => undefined;
  }
  const from = value.get();
  const start = performance.now();
  let raf = 0;
  const step = (now: number) => {
    const t = Math.min((now - start) / (duration * 1000), 1);
    value.set(from + (to - from) * ease(t), now);
    if (t < 1) {
      raf = requestAnimationFrame(step);
    } else {
      value.setCancel(null);
      onComplete?.();
    }
  };
  raf = requestAnimationFrame(step);
  const cancel = () => cancelAnimationFrame(raf);
  value.setCancel(cancel);
  return cancel;
}

interface SpringOptions {
  stiffness: number;
  damping: number;
  restDelta?: number;
  restSpeed?: number;
}

class SpringDriver {
  private vel = 0;
  private raf = 0;
  private last = 0;
  private running = false;
  private readonly restDelta: number;
  private readonly restSpeed: number;

  constructor(
    private readonly value: MotionValue,
    private readonly options: SpringOptions,
    private readonly getTarget: () => number,
    private readonly canRest: () => boolean = () => true
  ) {
    this.restDelta = options.restDelta ?? 5e-4;
    this.restSpeed = options.restSpeed ?? 0.005;
  }

  start() {
    if (this.running) {
      return;
    }
    this.value.stop();
    this.value.setCancel(() => this.stop());
    this.running = true;
    this.last = performance.now();
    const step = (now: number) => {
      if (!this.running) {
        return;
      }
      const dt = Math.min((now - this.last) / 1000, 0.033);
      this.last = now;
      const target = this.getTarget();
      const x = this.value.get();
      const accel =
        -this.options.stiffness * (x - target) - this.options.damping * this.vel;
      this.vel += accel * dt;
      const next = x + this.vel * dt;
      this.value.set(next, now);
      const settled =
        Math.abs(next - target) < this.restDelta &&
        Math.abs(this.vel) < this.restSpeed;
      if (settled && this.canRest()) {
        this.running = false;
        this.vel = 0;
        this.value.setCancel(null);
        this.value.set(target, now);
        return;
      }
      this.raf = requestAnimationFrame(step);
    };
    this.raf = requestAnimationFrame(step);
  }

  stop() {
    this.running = false;
    this.vel = 0;
    cancelAnimationFrame(this.raf);
  }
}

function rubberBand(distance: number, overshoot: number, dampening: number): number {
  if (overshoot <= 0 || distance === 0) {
    return 0;
  }
  const range = overshoot * dampening;
  const t = Math.min(1, Math.abs(distance) / range);
  return Math.sign(distance) * overshoot * (1 - (1 - t) ** 3);
}

function prefersReducedMotion(): boolean {
  return (
    typeof window !== "undefined" &&
    window.matchMedia("(prefers-reduced-motion: reduce)").matches
  );
}

export {
  cubicBezier,
  glassEase,
  MotionValue,
  PRESS_DURATION,
  prefersReducedMotion,
  RELEASE_DURATION,
  rubberBand,
  SpringDriver,
  TRAVEL_DURATION,
  tween,
};

